const rows = Array.isArray(msg.payload) ? msg.payload : [msg.payload];

const endpointDetailsById = {};

const options = rows
    .filter(r => r["Id"] && (r["Description"] || r["Name"]))
    .map(r => {
        const id = String(r["Id"]).trim();
        const name = String(r["Name"] || "").trim();
        const description = String(r["Description"] || "").trim();
        const location = String(r["Location"] || "").trim();

        const operatorLabel = description || name;

        endpointDetailsById[id] = {
            id,
            name,
            description,
            operatorLabel,
            location,
            ipAddress: String(r["IP Address"] || r["IPAddress"] || "").trim()
        };

        return {
            label: operatorLabel,
            value: id
        };
    })
    .sort((a, b) => a.label.localeCompare(b.label));

options.unshift({
