let walls = flow.get("walls") || {};

let selectedWallId = flow.get("selectedWallId") || "";
const wallName = (flow.get("editWallName") || "").trim();
const displayCount = Number(flow.get("editWallDisplayCount") || 0);

if (!wallName || displayCount < 1) {
    msg.payload = "Wall name and display count are required";
    return msg;
}

function makeWallId(name) {
    return name
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, "-")
        .replace(/^-|-$/g, "");
}

function makeDisplay(slot) {
    return {
        slot,
        label: `Display ${slot}`,
        endpointId: "",
        endpointLabel: "Unassigned",
        endpointName: "",
        endpointDescription: "",
        endpointLocation: "",
        layout: "1",
        windows: ["-1", "-1", "-1", "-1"]
    };
}

let wall;

// update existing wall
if (selectedWallId && walls[selectedWallId]) {
    wall = walls[selectedWallId];
    wall.wallName = wallName;

    const oldCount = wall.displays.length;

    if (displayCount > oldCount) {
        for (let i = oldCount + 1; i <= displayCount; i++) {
            wall.displays.push(makeDisplay(i));
        }
    } else if (displayCount < oldCount) {
        wall.displays = wall.displays.slice(0, displayCount);
    }

    wall.displayCount = displayCount;

    msg.payload = `Saved wall: ${wall.wallName}`;
}
// create new wall
else {
    const wallId = makeWallId(wallName);

    if (walls[wallId]) {
        msg.payload = "A wall with that name already exists";
        return msg;
    }

    const displays = [];
    for (let i = 1; i <= displayCount; i++) {
        displays.push(makeDisplay(i));
    }

    wall = {
        wallId,
        wallName,
        displayCount,
        displays
    };

    walls[wallId] = wall;
    selectedWallId = wallId;
    flow.set("selectedWallId", wallId);

    msg.payload = `Added wall: ${wall.wallName}`;
}

flow.set("walls", walls);

// useful for downstream nodes
msg.wallId = selectedWallId;
msg.wall = wall;

return msg;

